```cpp
// add_modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table names to corresponding C++ types
  std::map<std::string, rfl::TupleType> table_map = {
    {"Student", rfl::TupleType<Student>()},
    {"Course", rfl::TupleType<Course>()},
    {"Score", rfl::TupleType<Score>()},
    {"Major", rfl::TupleType<Major>()}
  };

  // Get the appropriate type from the table name
  auto type_it = table_map.find(table_name);
  if (type_it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Connect to database and insert records
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }

  auto conn = conn_result.value();

  // Create insert operation
  auto insert_op = sqlgen::insert_into(table_map[table_name]);

  // Execute the insert operation
  auto result = insert_op(conn, records.begin(), records.end());
  if (!result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const uint32_t record_id,
                               const std::string& col_name,
                               const std::optional<std::string>& new_value) {
  // Map table names to corresponding C++ types and primary key columns
  std::map<std::string, std::pair<rfl::TupleType, sqlgen::Col>> table_map = {
    {"Student", {rfl::TupleType<Student>(), "SNo"_c}},
    {"Course", {rfl::TupleType<Course>(), "CID"_c}},
    {"Score", {rfl::TupleType<Score>(), "ScID"_c}},
    {"Major", {rfl::TupleType<Major>(), "MID"_c}}
  };

  auto type_pair = table_map.find(table_name);
  if (type_pair == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  auto [record_type, pk_col] = type_pair->second;

  // Create column object for the specified column name
  auto col = sqlgen::Col<col_name>{};

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }

  auto conn = conn_result.value();

  // Create update operation
  auto update_op = sqlgen::update(record_type)(col.set(new_value));

  // Add where condition for the primary key
  auto where_op = update_op | sqlgen::where(pk_col == record_id);

  // Execute the update operation
  auto result = where_op(conn);
  if (!result) {
    throw std::runtime_error("Failed to update record");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const uint32_t record_id) {
  // Map table names to corresponding C++ types and primary key columns
  std::map<std::string, std::pair<rfl::TupleType, sqlgen::Col>> table_map = {
    {"Student", {rfl::TupleType<Student>(), "SNo"_c}},
    {"Course", {rfl::TupleType<Course>(), "CID"_c}},
    {"Score", {rfl::TupleType<Score>(), "ScID"_c}},
    {"Major", {rfl::TupleType<Major>(), "MID"_c}}
  };

  auto type_pair = table_map.find(table_name);
  if (type_pair == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  auto [record_type, pk_col] = type_pair->second;

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }

  auto conn = conn_result.value();

  // Create delete operation with where condition
  auto delete_op = sqlgen::delete_from(record_type) | sqlgen::where(pk_col == record_id);

  // Execute the delete operation
  auto result = delete_op(conn);
  if (!result) {
    throw std::runtime_error("Failed to delete record");
  }
}
```

## Key Implementation Details:

1. **Table Mapping**: Uses a `std::map` to associate table names with their corresponding C++ types and primary key columns.

2. **Error Handling**: Includes proper error checking for database connection and operation results.

3. **sqlgen Usage**:
   - Uses `sqlgen::insert_into` for batch inserts
   - Uses `sqlgen::update` with `set` and `where` for modifications
   - Uses `sqlgen::delete_from` with `where` for deletions
   - Leverages the pipe operator `|` for method chaining

4. **Type Safety**: Ensures that only valid table names are processed and provides compile-time type checking through the C++ struct definitions.

5. **Primary Key Handling**: Correctly identifies and uses the primary key column for WHERE conditions in update and delete operations.

The implementation follows sqlgen's fluent API pattern and properly handles the Result types returned by database operations.

