  auto final_query = sqlgen::select_from<DailyTrafficView>(
      "visit_date"_c,
      "total_visits"_c,
      "unique_pages"_c
  ) | sqlgen::order_by("visit_date"_c) | sqlgen::to<std::vector<DailyTraffic>>;

  return final_query(conn).value();
}

}  // namespace query_daily_traffic_metrics
