Based on the reference materials and detailed specifications, here's the complete implementation of the `soft_delete_records` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // Start transaction for atomicity
    auto transaction_result = conn->begin_transaction();
    if (!transaction_result) {
        return false;
    }

    try {
        // Iterate through each document ID and perform the update
        for (size_t i = 0; i < ids.size(); ++i) {
            // Create update statement using sqlgen::update
            auto update_stmt = sqlgen::update<Document>(
                "is_deleted"_c.set(1),
                "deleted_at"_c.set(sqlgen::CURRENT_TIMESTAMP)
            ) | sqlgen::where("doc_id"_c == ids[i]);

            // Execute the update
            auto result = update_stmt(conn);
            if (!result) {
                // Rollback on failure
                conn->rollback();
                return false;
            }
        }

        // Commit transaction if all updates succeed
        auto commit_result = conn->commit();
        return commit_result;

    } catch (...) {
        // Rollback on any exception
        conn->rollback();
        return false;
    }
}

}  // namespace soft_delete_records
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Transaction Management**: Starts transaction with `begin_transaction()` and commits/rolls back appropriately
3. **Update Construction**: Uses `sqlgen::update<Document>()` with `set()` methods for both `is_deleted` and `deleted_at` fields
4. **WHERE Clause**: Uses `sqlgen::where()` with equality condition (`"doc_id"_c == ids[i]`)
5. **Batch Processing**: Iterates through each ID in the vector for individual updates (as per sqlgen's preferred approach)
6. **Error Handling**: Properly handles connection errors, update failures, and exceptions with rollback

The implementation follows sqlgen's fluent API pattern and properly handles the soft delete mechanism by updating the `is_deleted` flag and `deleted_at` timestamp while maintaining transactional integrity.

